import React from "react";
import "../assets/styles/Timeline.scss";

interface TimelineItem {
  role: string;
  company: string;
  dates: string;
  description: string;
}

const timeline: TimelineItem[] = [
  {
    role: "Software Engineer",
    company: "Tech Mahindra",
    dates: "Jan 2022 - Present",
    description: "Worked on SAP Fiori automation testing, DevOps integration, and CI/CD pipelines.",
  },
  {
    role: "Project Management Practitioner",
    company: "Accenture",
    dates: "Jun 2020 - Dec 2021",
    description: "Managed dependencies, risks, and daily reports for multiple projects.",
  },
];

function Timeline() {
  return (
    <div id="timeline" className="timeline-container content-wrapper">
      <h2>Experience</h2>
      {timeline.map((item) => (
        <div className="timeline-card" key={item.role}>
          <div className="timeline-header">
            <h3>{item.role} @ {item.company}</h3>
            <span className="timeline-dates">{item.dates}</span>
          </div>
          <p>{item.description}</p>
        </div>
      ))}
    </div>
  );
}

export default Timeline;